const express = require('express');
const axios = require('axios');

const app = express();
app.use(express.json());

const cache = new Map();

app.post('/api/verify-nin', async (req, res) => {
  const { nin } = req.body;

  if (!nin) {
    return res.status(400).json({ error: 'NIN is required' });
  }

  if (cache.has(nin)) {
    return res.json(cache.get(nin));
  }

  try {
    const response = await axios.post(
      'https://api.prembly.com/verification/nin',
      { number: nin },
      {
        headers: {
          'app-id': process.env.PREMBLY_APP_ID,
          'x-api-key': process.env.PREMBLY_API_KEY
        }
      }
    );

    const data = response.data;
    cache.set(nin, data);
    return res.json(data);
  } catch (error) {
    const status = error.response ? error.response.status : 500;
    const data = error.response ? error.response.data : { error: 'Internal server error' };
    return res.status(status).json(data);
  }
});

const PORT = 3000;
app.listen(PORT, () => {
  console.log(`Server listening on port ${PORT}`);
});

